// extractChapterTitle scans text starting at pos, skipping separator chars,
// then collects consecutive ALL-CAPS words. Returns (title, endPos).
func extractChapterTitle(text string, pos int) (string, int) {
	seps := ". -\t\u2013\u2014"
	for pos < len(text) && strings.ContainsRune(seps, rune(text[pos])) {
		pos++
	}
	var words []string
	i := pos
	for i < len(text) {
		for i < len(text) && text[i] == ' ' {
			i++
		}
		j := i
		for j < len(text) && text[j] != ' ' && text[j] != '\t' && text[j] != '\n' {
			j++
		}
		word := text[i:j]
		if len(word) == 0 {
			break
		}
		// R04: collect alpha chars with explicit loop instead of comprehension
		var alpha []rune
		for _, c := range word {
			if unicode.IsLetter(c) {
				alpha = append(alpha, c)
			}
		}
		if len(alpha) == 0 { // R11: explicit length check
			if isAllDigits(word) {
				break
			}
			i = j
			continue
		}
		// R04: all-upper check with explicit loop
		allUpper := true
		for _, c := range alpha {
			if !unicode.IsUpper(c) {
				allUpper = false
				break
			}
		}
		if allUpper {
			words = append(words, strings.TrimRight(word, ".,;:"))
			i = j
		} else {
			break
		}
	}
	title := strings.TrimRight(strings.TrimSpace(strings.Join(words, " ")), ".,;:\u2013\u2014-")
	return title, i
}

func isAllDigits(s string) bool {
	if len(s) == 0 {
		return false
	}
	for _, c := range s {
		if !unicode.IsDigit(c) {
			return false
		}
	}
	return true
}

