// promoteStructuralLevels applies regex-based structural-level promotion to text.
// R05: uses []hitRecord slice and map[int][]int; R04: explicit loops throughout;
// R08: fmt.Sprintf for heading construction; R10: range over maps/slices;
// R11: explicit len checks instead of Python truthiness.
func promoteStructuralLevels(text string, structuralLevels [][2]interface{}, tocProximity int, stripTOC bool) string {
	// R04: build allHits with explicit nested loops
	var allHits []hitRecord
	for _, pair := range structuralLevels {
		patternStr := pair[0].(string)
		level := pair[1].(int)
		re := regexp.MustCompile(patternStr)
		for _, loc := range re.FindAllStringIndex(text, -1) {
			allHits = append(allHits, hitRecord{
				pos:    loc[0],
				end:    loc[1],
				marker: text[loc[0]:loc[1]],
				level:  level,
			})
		}
	}
	sort.Slice(allHits, func(a, b int) bool { return allHits[a].pos < allHits[b].pos })

	// R05: map[int][]int for byLevel; R04: explicit loop
	tocIdx := make(map[int]struct{})
	byLevel := make(map[int][]int)
	for idx, h := range allHits { // R10: range
		byLevel[h.level] = append(byLevel[h.level], idx)
	}
	for _, levelIndices := range byLevel { // R10: range map
		for k := 0; k < len(levelIndices)-1; k++ {
			ia, ib := levelIndices[k], levelIndices[k+1]
			if allHits[ib].pos-allHits[ia].pos < tocProximity {
				tocIdx[ia] = struct{}{}
				tocIdx[ib] = struct{}{}
			}
		}
	}

	// Replace right-to-left
	for i := len(allHits) - 1; i >= 0; i-- { // R09: reverse via explicit index
		h := allHits[i]
		if _, inTOC := tocIdx[i]; inTOC {
			if stripTOC {
				_, proseStart := extractChapterTitle(text, h.end)
				text = text[:h.pos] + text[proseStart:]
			}
			continue
		}
		hashes := strings.Repeat("#", h.level)
		title, proseStart := extractChapterTitle(text, h.end)
		heading := fmt.Sprintf("\n\n%s %s", hashes, h.marker) // R08
		if len(title) > 0 {                                    // R11
			heading += fmt.Sprintf(": %s", title)              // R08
		}
		heading += "\n\n"
		text = text[:h.pos] + heading + text[proseStart:]
	}
	return text
}

