// stripIndexParagraphs removes paragraphs whose index-line fraction >= threshold.
// R04: explicit loops replace comprehensions; R05: []string slice;
// R11: len check instead of truthiness; R13: RE2-compatible regex.
func stripIndexParagraphs(text string, indexLineThreshold float64) string {
	indexLineRE := regexp.MustCompile(`(?m)^.{2,60},\s*\d[\d,\s\-\x{2013}]*$`)
	paras := strings.Split(text, "\n\n")
	var cleaned []string // R05
	for _, para := range paras { // R10
		// R04: explicit loop instead of list comprehension
		var lines []string
		for _, l := range strings.Split(para, "\n") {
			if len(strings.TrimSpace(l)) > 0 { // R11
				lines = append(lines, l)
			}
		}
		if len(lines) == 0 { // R11
			cleaned = append(cleaned, para)
			continue
		}
		// R04: explicit count loop instead of sum(generator)
		indexCount := 0
		for _, l := range lines {
			if indexLineRE.MatchString(strings.TrimSpace(l)) {
				indexCount++
			}
		}
		if float64(indexCount)/float64(len(lines)) >= indexLineThreshold {
			continue // drop paragraph
		}
		cleaned = append(cleaned, para)
	}
	return strings.Join(cleaned, "\n\n")
}

