// mergeBlocks merges consecutive table-line and list-line paragraphs into
// atomic blocks joined by separator.
// R04: any() generators replaced with explicit hasTableLine/hasListLine helpers;
// R05: []string; R10: range; R11: explicit len checks.
func mergeBlocks(paragraphs []string, separator string) []string {
	var merged []string // R05
	for i := 0; i < len(paragraphs); { // R04: manual index loop
		para := paragraphs[i]
		var lines []string
		if strings.Contains(para, "\n") {
			lines = strings.Split(para, "\n")
		} else {
			lines = []string{para}
		}

		if anyTableLine(lines) { // R04: helper replaces any(generator)
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
					nextLines = strings.Split(paragraphs[j], "\n")
				} else {
					nextLines = []string{paragraphs[j]}
				}
				if anyTableLine(nextLines) {
					blockParts = append(blockParts, paragraphs[j])
					j++
				} else {
					break
				}
			}
			merged = append(merged, strings.Join(blockParts, separator))
			i = j
			continue
		}

		if anyListLine(lines) { // R04: helper replaces any(generator)
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
					nextLines = strings.Split(paragraphs[j], "\n")
				} else {
					nextLines = []string{paragraphs[j]}
				}
				if anyListLine(nextLines) {
					blockParts = append(blockParts, paragraphs[j])
					j++
				} else {
					break
				}
			}
			merged = append(merged, strings.Join(blockParts, separator))
			i = j
			continue
		}

		merged = append(merged, para)
		i++
	}
	return merged
}

