// run executes the full indexing pipeline for one source config.
// R01: pointer receiver on Indexer; R03: errors returned and checked explicitly;
// R04: explicit loop for text extraction; R05: []string, [][]float32;
// R06: nil for missing optional config values; R10: for i, batch := range;
// R11: len(embeddings) == 0 instead of truthiness.
func (idx *Indexer) run(sourceConfig map[string]interface{}) int {
	// R06: nil for missing string keys
	sourceID, _ := sourceConfig["source_id"].(string)
	domainID, _ := sourceConfig["domain_id"].(string)
	namespace, _ := sourceConfig["namespace"].(string)

	// R03: crawl errors surface via callback + early return
	allChunks, err := idx.crawl(sourceConfig)
	if err != nil {
		idx.onError("crawl", err)
		return 0
	}

	totalChunks := len(allChunks)
	idx.onProgress("crawl", totalChunks, totalChunks)
	idx.onProgress("chunk", totalChunks, totalChunks)

	if idx.abortFlag.Load() { // R11: explicit bool check
		idx.onAbort(0)
		return 0
	}

	// R04: explicit loop instead of list comprehension
	texts := make([]string, len(allChunks)) // R05
	for i, c := range allChunks {           // R10
		if idx.embedContentOnly {
			texts[i] = c.Content
		} else {
			if len(c.EmbeddingContent) > 0 { // R11
				texts[i] = c.EmbeddingContent
			} else {
				texts[i] = c.Content
			}
		}
	}

	totalBatches := totalChunks / idx.batchSize
	if totalChunks%idx.batchSize != 0 {
		totalBatches++
	}
	if totalBatches < 1 {
		totalBatches = 1
	}

	var allEmbeddings [][][]float32 // R05: slice of batches
	for batchIdx, start := 0, 0; start < totalChunks; batchIdx, start = batchIdx+1, start+idx.batchSize { // R10
		if idx.abortFlag.Load() { // R11
			idx.onAbort(0)
			return 0
		}
		end := start + idx.batchSize
		if end > totalChunks {
			end = totalChunks
		}
		batch := texts[start:end]
		vecs, err := idx.model.Encode(batch) // R03
		if err != nil {
			idx.onError("embed", err)
			return 0
		}
		allEmbeddings = append(allEmbeddings, vecs)
		idx.onProgress("embed", batchIdx+1, totalBatches)
	}

	if len(allEmbeddings) == 0 { // R11
		idx.onComplete(0)
		return 0
	}

	emb := flattenEmbeddings(allEmbeddings)

	if idx.abortFlag.Load() { // R11
		idx.onAbort(0)
		return 0
	}

	// R03: store errors surface via callback + early return
	if err := idx.store.AddDocument(allChunks, emb, namespace, sourceID, domainID); err != nil {
		idx.onError("store", err)
		return 0
	}
	idx.onProgress("store", totalChunks, totalChunks)
	idx.onComplete(totalChunks)
	return totalChunks
}

