// checkAll opens the global DB, lists all namespaces, then triggers async
// rebuilds for any stale namespace not already running.
// R01: pointer receiver on NamespaceRefresher; R03: errors checked with if err != nil;
// R04: explicit loop for namespace_ids; R05: []string; R07: defer con.Close();
// R10: for _, nsID := range; R11: explicit nil and len checks.
func (nr *NamespaceRefresher) checkAll() {
	// R03: surface error with early return
	globalDBPath, err := nr.dbPathFn("global")
	if err != nil {
		return
	}

	db, err := sql.Open("duckdb", globalDBPath+"?access_mode=read_only")
	if err != nil {
		return
	}
	defer db.Close() // R07: with → defer

	// R04: explicit loop instead of list comprehension
	rows, err := db.Query("SELECT namespace_id FROM namespaces")
	if err != nil {
		return
	}
	defer rows.Close() // R07
	var namespaceIDs []string // R05
	for rows.Next() {         // R10
		var nsID string
		if err := rows.Scan(&nsID); err != nil {
			return
		}
		namespaceIDs = append(namespaceIDs, nsID)
	}

	for _, nsID := range namespaceIDs { // R10
		// Check if already running under lock
		nr.lock.Lock()
		handle, exists := nr.active[nsID]
		nr.lock.Unlock()
		if exists && handle != nil && handle.Running() { // R11: explicit nil + bool check
			continue
		}

		// R03: store open/check errors → continue
		dbPath, err := nr.dbPathFn(nsID)
		if err != nil {
			continue
		}
		store, err := NewStore(dbPath, true)
		if err != nil {
			continue
		}
		valid, err := store.NamespaceCacheValid(nsID)
		store.Close()
		if err != nil {
			continue
		}

		if !valid { // R11: explicit bool
			nr.onRebuild(nsID)
			newHandle := buildNamespaceAsync(nsID, dbPath, nr.embedModel, nr.buildKwargs)
			nr.lock.Lock()
			nr.active[nsID] = newHandle
			nr.lock.Unlock()
		}
	}
}
